// Zero-result rescue: "did you mean" suggestions — the closest page titles
// by per-token edit distance. A dead-end empty state is never shown; the
// dialog renders these plus browse-section links instead.

export type Suggestion = { title: string; url: string };

/** Optimal-string-alignment distance (Levenshtein + adjacent transposition),
 * with an early bail when lengths differ by more than `cap`. */
export function osaDistance(a: string, b: string, cap = 6): number {
	if (a === b) return 0;
	if (Math.abs(a.length - b.length) > cap) return cap + 1;
	const n = b.length;
	let prev2: number[] = [];
	let prev = Array.from({ length: n + 1 }, (_, j) => j);
	for (let i = 1; i <= a.length; i++) {
		const curr = [i];
		for (let j = 1; j <= n; j++) {
			const cost = a[i - 1] === b[j - 1] ? 0 : 1;
			let d = Math.min(prev[j] + 1, curr[j - 1] + 1, prev[j - 1] + cost);
			if (i > 1 && j > 1 && a[i - 1] === b[j - 2] && a[i - 2] === b[j - 1]) {
				d = Math.min(d, prev2[j - 2] + 1);
			}
			curr.push(d);
		}
		prev2 = prev;
		prev = curr;
	}
	return prev[n];
}

function words(s: string): string[] {
	return s
		.toLowerCase()
		.split(/[^a-z0-9]+/)
		.filter(Boolean);
}

/**
 * Closest page titles for a zero-result query. Per query token, take the best
 * (prefix-aware) edit distance to any title token; average across tokens.
 * Always returns up to `max` entries.
 */
export function zeroResultSuggestions(
	query: string,
	entries: readonly { title: string; url: string }[],
	max = 3,
): Suggestion[] {
	const qTokens = words(query).filter((t) => t.length > 1);
	if (qTokens.length === 0) return [];

	const scored = entries.map((entry) => {
		const tTokens = words(entry.title);
		let total = 0;
		for (const q of qTokens) {
			let best = q.length; // worst case: replace everything
			for (const t of tTokens) {
				let d = osaDistance(q, t);
				// Prefix-aware: "workt" is close to "worktreecreate".
				if (t.length > q.length) {
					d = Math.min(d, osaDistance(q, t.slice(0, q.length)) + 0.5);
				}
				if (d < best) best = d;
			}
			total += best;
		}
		return { entry, score: total / qTokens.length };
	});

	return scored
		.sort((a, b) => a.score - b.score)
		.slice(0, max)
		.map(({ entry }) => ({ title: entry.title, url: entry.url }));
}
